VALUES
  ('real-estate-moex-00894', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列何種情形免徵契稅？ 以遷移、補償等變相方式支付產價，取得不動產所有權者 依法領買或標購公產及向法院標購拍賣之不動產者 開徵土地增值稅區域之土地 以不動產為信託財產，受託人依信託本旨移轉信託財產與委託人以外之歸屬權利人時', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00895', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列何者是土地增值稅的課稅基礎？ 累進起點地價  公告土地現值  土地漲價總數額  申報地價', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00896', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列有關規定地價之規定，何者錯誤？ 規定地價後，每2年重新規定地價一次。但必要時得延長之。重新規定地價者，亦同。 舉辦規定地價或重新規定地價時，土地所有權人未於公告期間申報地價者，以公告地價 80%為其申報 地價 已規定地價之土地，應按申報地價，依法徵收地價稅 直轄市或縣（市）主管機關為辦理規定地價，應分區調查最近2年之土地買賣價格或收益價格', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00897', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列有關外國人取得我國土地之規定，何者正確？ 外國人依土地法規定取得土地時，應檢附相關文件，申請內政部核准 農、林、漁、牧用地不得移轉、設定負擔或租賃於外國人 外國人依土地法規定取得之土地，其面積及所在地點，應受該管直轄市或縣（市）政府依法所定之限制 外國人為有助於國內重大建設、整體經濟或農牧經營之投資所取得之土地，應先經行政院核准', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00898', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '個人及營利事業出售依農業發展條例申請興建的農舍，應如何計徵所得稅？ 依104年12月31日前實施之舊制，僅就土地部分計算財產交易所得，課徵綜合所得稅 依104年12月31日前實施之舊制，僅就房屋部分計算財產交易所得，課徵綜合所得稅 依105年1月1日起實施之新制，房屋、土地均應按實價計算交易所得課稅 不論新、舊制，均免徵所得稅', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00899', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列有關契稅之申報起算日規定，何者錯誤？ 不動產移轉發生糾紛時，其申報契稅之起算日期，應以法院判決確定日為準 向政府機關標購或領買公產，以政府機關核發產權移轉證明書之日為申報起算日 向法院標購拍賣之不動產，以法院發給權利移轉證明書之日為申報起算日 不動產分割時，以其完成移轉登記之日為申報起算日', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00900', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列何者非申請自住房屋稅稅率之要件？ 土地所有權人或其配偶、直系親屬於房屋所在地辦竣戶籍登記 房屋無出租使用 供本人、配偶或直系親屬實際居住使用 本人、配偶及未成年子女全國合計3戶以內', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00901', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲之土地於106年10月1日贈與並移轉登記予乙，請問106年期地價稅之納稅義務人為何？ 甲    乙 甲乙協議    甲乙依持有月數分別負擔', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00902', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲之土地、房屋於106年7月1日設定典權並完成移轉登記予乙。下列有關納稅義務人之規定，何者錯誤？ 當年度地價稅之納稅義務人為甲  107年期房屋稅之納稅義務人為乙 典權契稅之納稅義務人為乙  土地增值稅之納稅義務人為甲', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00903', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲出售市價2,000萬元之房屋連同基地，出售時土地公告現值總額為1,000萬元，房屋課稅現值為300萬 元，繳納土地增值稅 100 萬元。如果甲符合自用住宅用地之規定，請問甲至少應買多少錢之房屋土地才 能申請退還土地增值稅100萬元？ 不問市價，只要新購土地之公告土地現值大於900萬元 不問市價，只要新購土地之公告土地現值大於1,000萬元 新購之房屋現值大於300萬元，房屋連同基地之市價大於2,000萬元 新購房屋連同基地之市價大於2,000萬元', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00904', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地稅法規定農業用地移轉與自然人時，得申請不課徵土地增值稅。此處所稱農業用地，下列規定何者 錯誤？ 農業發展條例第3條第11款所稱之耕地 依區域計畫法劃定為各種使用分區內所編定之林業用地、養殖用地、水利用地、生態保護用地、國土 保安用地及供農路使用之土地，或上開分區內暫未依法編定用地別之土地 依區域計畫法劃定為農業區、山坡地保育區、森林區以外之分區內所編定之農牧用地 依都市計畫法劃定為農業區、保護區內之土地', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00905', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '被徵收之土地，有下列何種情形時，原土地所有權人得於徵收公告之日起20年內，向該管直轄市或縣（市） 主管機關申請照原徵收補償價額收回其土地？ 徵收補償費發給完竣屆滿2年，未依徵收計畫開始使用者 徵收土地之殘餘部分面積過小或形勢不整，致不能為相當之使用者 未依核准徵收原定興辦事業使用者 依原徵收計畫開始使用後未滿6年，不繼續依原徵收計畫使用者', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00906', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列何者為撤銷徵收之原因？ 因工程變更設計，致原徵收之土地不在工程用地範圍內 公告徵收時，都市計畫已規定以聯合開發、市地重劃或其他方式開發。但以聯合開發方式開發之土地， 土地所有權人不願參與聯合開發者，不在此限 依徵收計畫開始使用前，興辦之事業改變、興辦事業計畫經註銷、開發方式改變或取得方式改變 已依徵收計畫開始使用，尚未依徵收計畫完成使用之土地，因情事變更，致原徵收土地之全部或一部 已無徵收之必要', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00907', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列有關違反區域計畫管制使用土地者之處罰規定，何者錯誤？ 由該管直轄市、縣（市）政府處新臺幣6萬元以上30萬元以下罰鍰 經限期變更使用、停止使用或拆除地上物恢復原狀而不遵從者，得按次處罰 經限期變更使用而不遵從者，並得停止供水、供電、封閉、強制拆除或採取其他恢復原狀之措施 不依限變更土地使用者，除依強制執行法辦理外，並得處6個月以下有期徒刑或拘役', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00908', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列何者非區域計畫法規定區域計畫得隨時檢討變更之原因？ 發生或避免重大災害    興辦重大開發或建設事業 為適應國防或經濟發展之需要  區域建設推行委員會之建議', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00909', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列有關都市計畫法中公共設施用地之設置規定，何者錯誤？ 公共設施用地，應就人口、土地使用、交通等現狀及未來發展趨勢，決定其項目、位置與面積 公園、體育場所、綠地、廣場及兒童遊樂場，應依計畫人口密度及自然環境，作有系統之布置，除具 有特殊情形外，其占用土地總面積不得少於全部計畫面積10% 道路系統、停車場所及加油站，應按土地使用分區及交通情形與預期之發展配置之。鐵路、公路通過 實施都市計畫之區域者，應避免穿越市區中心', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00910', 'real-estate', 'real-estate-moex-106-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依都市計畫法第22條規定，下列何者非細部計畫應以細部計畫書及細部計畫圖應表明之事項？ 名勝、古蹟及具有紀念性或藝術價值應予保存之建築 居住密度及容納人口 土地使用分區管制 道路系統', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:38+00:00", "source_pdf_sha1": "7683dcdc6e14", "answer_pdf_sha1": "dd4ee37e17bc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL);
